import { useNavigate } from 'react-router-dom';
import './SideNav.css';

function SideNav({ logout, isNavOpen, setIsNavOpen }) {
  const navigate = useNavigate();

  const toggleNav = () => {
    setIsNavOpen(isNavOpen); // Toggle the side navigation visibility
  };

  // Handler functions for navigation
  const goToHome = () => navigate('/HomePage');
  const goToChat = () => navigate('/ChatBox');
  //const goToSettings = () => navigate('/Settings');

  return (
    <div className="side-nav-container">
      {/* Side Navigation - Visible when 'isOpen' is true */}
      <div className={`side-nav ${isNavOpen ? 'open' : ''}`}>
        <ul>
          <li>
            <button onClick={goToHome}>Home</button> {/* Use button to navigate to Home */}
          </li>
          <li>
            <button onClick={goToChat}>Chat</button> {/* Use button to navigate to Chat */}
          </li>
          {/*<li>
               <button onClick={goToSettings}>Settings</button>
            </li>*/}
          {/* Logout button inside SideNav */}
          <li>
            <button onClick={logout}>Logout</button> {/* Logout button */}
          </li>
        </ul>
      </div>

      {/* Arrow button */}
      <div className={`arrow ${isNavOpen ? 'rotate' : ''}`} onClick={toggleNav}>
        &#x2192; {/* Rectangular rightwards arrow */}
      </div>
    </div>
  );
}

export default SideNav;
